FILES['app/build.gradle'] = 'plugins {\n    id \'com.android.application\'\n}\n\nandroid {\n    namespace \'com.neroflix.tv.app\'\n    compileSdk 34\n\n    defaultConfig {\n        applicationId "com.neroflix.tv.app"\n        minSdk 21\n        targetSdk 34\n        versionCode 41\n        versionName "1.4.6"\n\n        ndk {\n            abiFilters \'arm64-v8a\', \'armeabi-v7a\'\n        }\n\n        buildConfigField "String", "TMDB_API_KEY", "\\"${project.findProperty(\'TMDB_API_KEY\') ?: \'YOUR_TMDB_API_KEY_HERE\'}\\""\n        buildConfigField "String", "TMDB_BASE_URL", "\\"https://api.themoviedb.org/3\\""\n        buildConfigField "String", "TMDB_IMAGE_BASE", "\\"https://image.tmdb.org/t/p\\""\n    }\n\n    signingConfigs {\n        release {\n            storeFile file(System.getenv("SIGNING_STORE_FILE") ?: "nero.keystore")\n            storePassword "Neroflix2025"\n            keyAlias "nero"\n            keyPassword "Neroflix2025"\n        }\n    }\n\n    buildTypes {\n        debug {\n            versionNameSuffix "-debug"\n            debuggable true\n        }\n        release {\n            debuggable false\n            minifyEnabled true\n            shrinkResources true\n            proguardFiles getDefaultProguardFile(\'proguard-android-optimize.txt\'), \'proguard-rules.pro\'\n            signingConfig signingConfigs.release\n        }\n    }\n\n    packagingOptions {\n        // Strip unused native libs\n        resources {\n            excludes += [\n                \'META-INF/DEPENDENCIES\',\n                \'META-INF/LICENSE\',\n                \'META-INF/LICENSE.txt\',\n                \'META-INF/NOTICE\',\n                \'META-INF/NOTICE.txt\',\n                \'META-INF/*.kotlin_module\',\n                \'**/*.kotlin_builtins\',\n                \'**/*.kotlin_metadata\',\n                \'DebugProbesKt.bin\'\n            ]\n        }\n    }\n\n    compileOptions {\n        sourceCompatibility JavaVersion.VERSION_17\n        targetCompatibility JavaVersion.VERSION_17\n    }\n\n    buildFeatures {\n        buildConfig true\n        viewBinding true\n    }\n\n    // Fix: disable lint checks that block release builds\n    lint {\n        abortOnError false\n        disable \'DuplicatePlatformClasses\', \'ResourceCycle\', \'InvalidSetHasFixedSize\', \'MissingDefaultResource\'\n    }\n\n}\n\ndependencies {\n    // BASS + BASSMIDI (un4seen Developments — https://www.un4seen.com):\n    // real-time MIDI synthesis via BassMidiAudioEngine, used when\n    // available with automatic fallback to MediaPlayer otherwise.\n    // BASS core is bundled directly as source\n    // (app/src/main/java/com/un4seen/bass/BASS.java) plus real\n    // libbass.so per ABI — no jar needed for it. This line is for the\n    // still-pending BASSMIDI add-on, if it\'s supplied as a jar rather\n    // than source: drop bassmidi.jar into app/libs/ to activate it.\n    // Native .so files for BASSMIDI also still need to go in\n    // app/src/main/jniLibs/<abi>/ — see app/libs/README.md for the\n    // full setup checklist. Non-commercial/freeware use of BASS is\n    // free; commercial/shareware distribution requires a paid license\n    // from un4seen — check current terms before shipping.\n    implementation fileTree(dir: \'libs\', include: [\'*.jar\'])\n\n    // AndroidX Core\n    implementation \'androidx.appcompat:appcompat:1.6.1\'\n    implementation \'com.google.android.material:material:1.11.0\'\n    implementation \'androidx.constraintlayout:constraintlayout:2.1.4\'\n    implementation \'androidx.recyclerview:recyclerview:1.3.2\'\n    implementation \'androidx.swiperefreshlayout:swiperefreshlayout:1.1.0\'\n    implementation \'androidx.core:core:1.12.0\'\n\n    // Networking\n    implementation \'com.squareup.okhttp3:okhttp:4.12.0\'\n    // Removed org.json:json — Android already includes org.json built-in\n\n    // Image Loading\n    implementation \'com.github.bumptech.glide:glide:4.16.0\'\n    implementation \'org.mozilla.geckoview:geckoview:125.0.20240408174943\'\n    annotationProcessor \'com.github.bumptech.glide:compiler:4.16.0\'\n\n    // Leanback for TV (D-pad)\n    implementation \'androidx.leanback:leanback:1.0.0\'\n\n    // ExoPlayer with DASH, HLS, DRM support\n    implementation \'androidx.media3:media3-exoplayer:1.3.1\'\n    implementation \'androidx.media3:media3-exoplayer-hls:1.3.1\'\n    implementation \'androidx.media3:media3-exoplayer-dash:1.3.1\'\n    implementation \'androidx.media3:media3-ui:1.3.1\'\n    implementation \'androidx.media3:media3-session:1.3.1\'\n    implementation \'androidx.media3:media3-datasource-okhttp:1.3.1\'\n    implementation \'androidx.media3:media3-exoplayer-smoothstreaming:1.3.1\'\n    implementation \'androidx.media3:media3-exoplayer-rtsp:1.3.1\'\n\n    // Palette for dynamic colors\n    implementation \'androidx.palette:palette:1.0.0\'\n}\n'

FILES['app/libs/README.md'] = '# BASSMIDI Java library goes here (BASS core is already bundled)\n\n**BASS core is already fully integrated** — the real `BASS.java` source\nfrom un4seen is bundled directly at\n`app/src/main/java/com/un4seen/bass/BASS.java`, and the real\n`libbass.so` binaries are bundled per-ABI in `app/src/main/jniLibs/`.\nNo jar needed for BASS core; nothing to add for it.\n\n**Still needed: the BASSMIDI add-on**, which is what actually creates a\nplayable stream from a MIDI file and loads SoundFonts (.sf2). BASS core\nalone can\'t do MIDI synthesis — it needs this add-on. To add it:\n\n1. Download the **BASSMIDI** package for Android from\n   https://www.un4seen.com/ (a separate download from BASS core — look\n   for the BASSMIDI add-on, matching your BASS version).\n2. If it includes Java source (`BASSMIDI.java`), copy it to\n   `app/src/main/java/com/un4seen/bass/BASSMIDI.java` — same treatment\n   as `BASS.java`. If it only ships a compiled `bassmidi.jar`, drop\n   that jar in this folder (`app/libs/`) instead — either way,\n   `BassMidiAudioEngine.java` picks it up automatically (it currently\n   reaches BASSMIDI reflectively specifically so it doesn\'t matter\n   which form you have).\n3. Copy the matching `libbassmidi.so` into\n   `app/src/main/jniLibs/<abi>/` — see the README there.\n4. Rebuild. Check logcat (`adb logcat -s KaraokeAudioEngine`) — it\n   logs which engine actually got used for each song, and will show\n   `"BASSMIDI (native)"` once this step is done correctly.\n\n**Licensing:** BASS is free for non-commercial/freeware use. Commercial\nor shareware distribution requires a paid license from un4seen — check\nhttps://www.un4seen.com/bass.html for current terms before shipping.\n'

FILES['app/src/main/jniLibs/README.md'] = "# Native libraries\n\n**`libbass.so` is already bundled** for all four ABIs\n(`armeabi-v7a`, `arm64-v8a`, `x86`, `x86_64`) — nothing to add for\nBASS core.\n\n**Still needed: `libbassmidi.so`** (the BASSMIDI add-on's native\nlibrary — see `app/libs/README.md` for where to get it), placed\nalongside `libbass.so` in the matching folder:\n\n```\napp/src/main/jniLibs/armeabi-v7a/libbass.so       ✅ already here\napp/src/main/jniLibs/armeabi-v7a/libbassmidi.so   ← add this\napp/src/main/jniLibs/arm64-v8a/libbass.so         ✅ already here\napp/src/main/jniLibs/arm64-v8a/libbassmidi.so     ← add this\napp/src/main/jniLibs/x86/libbass.so               ✅ already here\napp/src/main/jniLibs/x86/libbassmidi.so           ← add this\napp/src/main/jniLibs/x86_64/libbass.so            ✅ already here\napp/src/main/jniLibs/x86_64/libbassmidi.so        ← add this\n```\n\nMost real Android devices only need `arm64-v8a` (and `armeabi-v7a` for\nolder devices) — `x86`/`x86_64` are mainly for emulators, so it's fine\nto skip `libbassmidi.so` for those if you don't need emulator testing.\n\nSee `app/libs/README.md` for the full checklist and licensing note.\n"


def main():
    repo_root = os.getcwd()
    changed = []
    for relpath, content in FILES.items():
        full_path = os.path.join(repo_root, relpath)
        os.makedirs(os.path.dirname(full_path), exist_ok=True)
        with open(full_path, "w", encoding="utf-8", newline="\n") as f:
            f.write(content)
        changed.append(relpath)

    print("Updated/created files:")
    for r in changed:
        print("  -", r)

    bass_so = os.path.join(repo_root, "app/src/main/jniLibs/arm64-v8a/libbass.so")
    print()
    if os.path.exists(bass_so):
        print("libbass.so found in jniLibs — BASS core native library is in place.")
    else:
        print("NOTE: libbass.so not found yet under app/src/main/jniLibs/.")
        print("Extract bass_native_libs.zip into app/src/main/ before building:")
        print("  unzip -o ~/Download/bass_native_libs.zip -d app/src/main/")

    print()
    print("BASSMIDI (the add-on that actually plays MIDI + loads SoundFonts)")
    print("is still a separate download you need to add yourself -- see")
    print("app/libs/README.md for exactly what is needed.")
    print()
    print("Now commit and push, e.g.:")
    print("  git add -A")
    print('  git commit -m "Integrate real BASS core SDK (source + native libs), BASSMIDI still pending"')
    print("  git push")

if __name__ == "__main__":
    main()
